@app.on_event("startup")
def _startup() -> None:
    _ensure_tables()


def _save_attempt(voucher_url: str, status: str, amount: str = "", detail: str = "", package_id: str = "", expected_amount: float = 0.0, group_id: str = "") -> str:
    _ensure_tables()
    attempt_id = uuid.uuid4().hex
    conn = _conn()
    cur = conn.cursor()
    cur.execute(
        """
        INSERT INTO payment_attempts
            (id, created_at, voucher_url, amount, status, detail, package_id, expected_amount, group_id, link_status, join_status)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, 'selected', 'pending')
        """,
        (attempt_id, int(time.time()), voucher_url, amount, status, detail, package_id, expected_amount, group_id),
    )
    conn.commit()
    conn.close()
    return attempt_id


def _safe_amount(value) -> float:
    try:
        return float(str(value).strip())
    except Exception:
        return 0.0


def _update_attempt(attempt_id: str, status: str, amount: str = "", detail: str = "", link_status: str | None = None, invite_link: str | None = None, invite_error: str | None = None) -> None:
    _ensure_tables()
    conn = _conn()
    cur = conn.cursor()
    sets = ["status=?", "amount=?", "paid_amount=?", "detail=?"]
    params: list[object] = [status, amount, _safe_amount(amount), detail]
    if link_status is not None:
        sets.append("link_status=?")
        params.append(link_status)
    if invite_link is not None:
        sets.append("invite_link=?")
        params.append(invite_link)
    if invite_error is not None:
        sets.append("invite_error=?")
        params.append(invite_error)
    params.append(attempt_id)
    cur.execute(f"UPDATE payment_attempts SET {', '.join(sets)} WHERE id=?", params)
    conn.commit()
    conn.close()


def _amount_matches(paid: float, expected: float) -> bool:
    return expected > 0 and abs(float(paid) - float(expected)) < 0.01


def _bot_invite_ready(group_id: str) -> tuple[bool, str]:
    group_id = (group_id or "").strip()
    if not BOT_TOKEN:
        return False, "missing BOT_TOKEN"
    if not group_id:
        return False, "missing Telegram Group ID"
    try:
        chat_id = int(group_id) if group_id.lstrip("-").isdigit() else group_id
        me_res = requests.get(f"https://api.telegram.org/bot{BOT_TOKEN}/getMe", timeout=10)
        me_data = me_res.json()
        if not me_data.get("ok") or not me_data.get("result", {}).get("id"):
            return False, "bot token is not valid"
        bot_id = int(me_data["result"]["id"])
        member_res = requests.get(
            f"https://api.telegram.org/bot{BOT_TOKEN}/getChatMember",
            params={"chat_id": chat_id, "user_id": bot_id},
            timeout=10,
        )
        member_data = member_res.json()
        if not member_data.get("ok"):
            return False, str(member_data.get("description") or "cannot check bot member status")
        member = member_data.get("result", {})
        status = str(member.get("status") or "")
        if status not in ("administrator", "creator"):
            return False, "bot must be an admin in this group"
        if status == "administrator" and member.get("can_invite_users") is False:
            return False, "bot admin permission must allow invite users"
        return True, ""
    except Exception as exc:
        return False, str(exc)


