def _create_single_use_invite_link(group_id: str) -> str:
    group_id = (group_id or "").strip()
    ready, _reason = _bot_invite_ready(group_id)
    if not ready:
        return ""
    try:
        chat_id = int(group_id) if group_id.lstrip("-").isdigit() else group_id
        res = requests.post(
            f"https://api.telegram.org/bot{BOT_TOKEN}/createChatInviteLink",
            json={"chat_id": chat_id, "member_limit": 1, "expire_date": int(time.time()) + 900},
            timeout=12,
        )
        data = res.json()
        if data.get("ok") and data.get("result", {}).get("invite_link"):
            return str(data["result"]["invite_link"])
    except Exception:
        return ""
    return ""


def _process_attempt(attempt_id: str, voucher_url: str) -> None:
    if not voucher_url.startswith("https://gift.truemoney.com/campaign/"):
        _update_attempt(attempt_id, "invalid", detail="รูปแบบลิงก์ไม่ถูกต้อง")
        return

    conn = _conn()
    cur = conn.cursor()
    cur.execute(
        """
        SELECT id FROM payment_attempts
        WHERE voucher_url = ?
          AND id != ?
          AND status IN ('success', 'duplicate', 'already_confirmed', 'amount_mismatch', 'insufficient', 'voucher_used', 'used_voucher')
        LIMIT 1
        """,
        (voucher_url, attempt_id),
    )
    duplicate_row = cur.fetchone()
    conn.close()
    if duplicate_row:
        _update_attempt(attempt_id, "duplicate", detail="voucher already checked or approved")
        return

    result = _redeem_voucher(voucher_url)
    paid_amount = _safe_amount(result.get("amount") or "")
    conn = _conn()
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()
    cur.execute("SELECT expected_amount, group_id FROM payment_attempts WHERE id=?", (attempt_id,))
    row = cur.fetchone()
    conn.close()
    expected_amount = _safe_amount(row["expected_amount"] if row else 0)
    group_id = str(row["group_id"] if row else "")

    if result.get("ok") and not _amount_matches(paid_amount, expected_amount):
        mismatch_status = "insufficient" if paid_amount < expected_amount else "amount_mismatch"
        mismatch_link_status = "insufficient" if paid_amount < expected_amount else "paid_mismatch"
        _update_attempt(
            attempt_id,
            mismatch_status,
            amount=str(result.get("amount") or ""),
            detail=f"ยอดที่จ่าย {paid_amount:g} ไม่ตรงกับแพ็กเกจ {expected_amount:g}",
            link_status=mismatch_link_status,
        )
        return

    if result.get("ok"):
        ready, invite_error = _bot_invite_ready(group_id)
        if not ready:
            _update_attempt(attempt_id, "success", amount=str(result.get("amount") or ""), detail="paid but bot is not ready to issue invite", link_status="paid", invite_error=invite_error)
            return
        invite_link = _create_single_use_invite_link(group_id)
        if invite_link:
            _update_attempt(attempt_id, "success", amount=str(result.get("amount") or ""), detail="paid and issued", link_status="issued", invite_link=invite_link)
        else:
            _update_attempt(attempt_id, "success", amount=str(result.get("amount") or ""), detail="paid but invite link was not issued", link_status="paid", invite_error="createChatInviteLink failed")
        return

    result_code = str(result.get("code") or "")
    if result_code == "api_error":
        _update_attempt(attempt_id, "api_error", amount=str(result.get("amount") or ""), detail=str(result.get("message") or ""), link_status="api_error")
    elif result_code == "used":
        _update_attempt(attempt_id, "voucher_used", amount=str(result.get("amount") or ""), detail=str(result.get("message") or ""), link_status="voucher_used")
    else:
        _update_attempt(attempt_id, "failed", amount=str(result.get("amount") or ""), detail=str(result.get("message") or ""), link_status="failed")


def _redeem_voucher(voucher_url: str) -> dict:
    if not API_KEY or not PHONE_NUMBER:
        return {"ok": False, "code": "api_error", "message": "ยังไม่ได้ตั้งค่า API_KEY หรือ PHONE_NUMBER"}

    payload = {
        "key": API_KEY,
        "phone": PHONE_NUMBER,
        "gift_link": voucher_url,
    }
    try:
        res = requests.post(API_URL, data=payload, timeout=20)
        try:
            data = res.json()
        except Exception:
            data = {"raw": res.text}
    except Exception as exc:
        return {"ok": False, "code": "api_error", "message": f"เชื่อมต่อ API ไม่สำเร็จ: {exc}"}

    text_blob = str(data).lower()
    ok = res.ok and any(k in text_blob for k in ("success", "สำเร็จ", "true", "amount"))
    code = ""
    if not res.ok:
        code = "api_error"
    elif any(k in text_blob for k in ("used", "redeemed", "already", "ถูกใช้", "ใช้ไปแล้ว", "รับไปแล้ว")):
        code = "used"
    elif any(k in text_blob for k in ("not found", "invalid", "ไม่พบ", "ไม่ถูกต้อง")):
        code = "not_found"
    amount = ""
    for key in ("amount", "money", "value"):
        if isinstance(data, dict) and data.get(key) is not None:
            amount = str(data.get(key))
            break
    return {"ok": ok, "amount": amount, "code": code, "message": str(data)}


