def _voucher_short_from_url(voucher_url: str) -> str:
    text = str(voucher_url or "")
    match = re.search(r"[?&]v=([^&\s]+)", text)
    code = match.group(1) if match else text
    return code[:14] + "…" + code[-8:] if len(code) > 28 else code


def _attempt_history_status(row: sqlite3.Row) -> tuple[str, str, str]:
    flow = _attempt_flow_snapshot(row)
    kind = str(flow.get("kind") or "")
    link_status = str(row["link_status"] or "") if "link_status" in row.keys() else ""
    join_status = str(row["join_status"] or "") if "join_status" in row.keys() else ""

    if kind == "failed":
        return "จ่ายไม่สำเร็จ", "bad", ""
    if kind == "duplicate":
        return "ซองนี้เคยตรวจแล้ว", "wait", ""
    if kind == "insufficient":
        return "ยอดไม่พอ", "bad", ""
    if kind == "used_voucher":
        return "ซองถูกใช้แล้ว", "bad", ""
    if kind == "system_error":
        return "ระบบตรวจสอบขัดข้อง", "wait", ""
    if join_status == "joined" or kind == "joined":
        return "เข้ากลุ่มสำเร็จ", "good", ""
    if link_status == "used" or kind == "used":
        username = str(row["joined_username"] or "") if "joined_username" in row.keys() else ""
        full_name = str(row["joined_full_name"] or "") if "joined_full_name" in row.keys() else ""
        joined_user_id = str(row["joined_user_id"] or "") if "joined_user_id" in row.keys() else ""
        who = f"@{username}" if username else (full_name or (f"uid {joined_user_id}" if joined_user_id else ""))
        return "ลิงก์นี้ถูกใช้ไปแล้ว", "used", who
    if kind in ("issued", "paid", "checking"):
        return "รอการเข้ากลุ่ม", "wait", ""
    return "จ่ายไม่สำเร็จ", "bad", ""


def _row_to_public_dict(row: sqlite3.Row) -> dict:
    data: dict[str, object] = {}
    for key in row.keys():
        value = row[key]
        if key == "voucher_url" and value:
            data["voucher_ref"] = _voucher_short_from_url(str(value))
            continue
        data[key] = value
    return data


def _attempt_snapshot(attempt_id: str) -> dict:
    result_data = get_verified_result(attempt_id)
    return {
        "ok": True,
        "attempt_id": attempt_id,
        "result_api": result_data,
        "source": result_data.get("source", "result_api"),
    }


def _render_attempt_history_item(row: sqlite3.Row, time_format: str = "%H:%M") -> str:
    short_code = _voucher_short_from_url(str(row["voucher_url"] or ""))
    try:
        ts_text = time.strftime(time_format, time.localtime(int(row["created_at"] or 0)))
    except Exception:
        ts_text = "-"
    amount_value = row["paid_amount"] if "paid_amount" in row.keys() and row["paid_amount"] not in (None, "") else row["expected_amount"]
    amount = ""
    if amount_value not in (None, ""):
        try:
            amount = f"<span class='history-amount'>{float(amount_value):g} บาท</span>"
        except Exception:
            amount = f"<span class='history-amount'>{escape(str(amount_value))} บาท</span>"
    status_text, status_kind, who = _attempt_history_status(row)
    who_html = f"<span class='history-who'>{escape(who)}</span>" if who else ""
    status_html = f"<div class='history-status history-status-{status_kind}'>{escape(status_text)}{who_html}</div>"
    return (
        "<div class='history-item'>"
        f"<div class='history-code'>ซอง {escape(short_code)}</div>"
        f"<div class='history-time'>{escape(ts_text)}</div>"
        f"{amount}"
        f"{status_html}"
        "</div>"
    )


def _render_attempt_history_item_split(row: sqlite3.Row) -> str:
    short_code = _voucher_short_from_url(str(row["voucher_url"] or ""))
    try:
        date_text = time.strftime("%d/%m/%Y", time.localtime(int(row["created_at"] or 0)))
        time_text = time.strftime("%H:%M", time.localtime(int(row["created_at"] or 0)))
    except Exception:
        date_text = "-"
        time_text = ""
    amount_value = row["paid_amount"] if "paid_amount" in row.keys() and row["paid_amount"] not in (None, "") else row["expected_amount"]
    amount = ""
    if amount_value not in (None, ""):
        try:
            amount = f"<span class='history-amount'>{float(amount_value):g} บาท</span>"
        except Exception:
            amount = f"<span class='history-amount'>{escape(str(amount_value))} บาท</span>"
    status_text, status_kind, who = _attempt_history_status(row)
    who_html = f"<span class='history-who'>{escape(who)}</span>" if who else ""
    return (
        "<div class='history-item'>"
        f"<div class='history-code'>ซอง {escape(short_code)}</div>"
        f"<div class='history-time'><span>{escape(date_text)}</span><span>{escape(time_text)}</span></div>"
        f"{amount}"
        f"<div class='history-status history-status-{status_kind}'>{escape(status_text)}{who_html}</div>"
        "</div>"
    )


def _split_status_icon(title: str) -> tuple[str, str]:
    text = str(title or "").strip()
    for icon in ("❗️", "⚠️", "❌", "✅", "↻"):
        if text.startswith(icon):
            return icon, text[len(icon):].strip()
    return "", text


def _status_symbol_html(icon: str) -> str:
    if icon == "❌":
        return (
            '<span class="result-state-symbol result-state-symbol-x" aria-hidden="true">'
            '<svg viewBox="0 0 24 24">'
            '<line class="x-a" x1="7" y1="7" x2="17" y2="17"/>'
            '<line class="x-b" x1="17" y1="7" x2="7" y2="17"/>'
            '</svg></span>'
        )
    if icon == "⚠️":
        return (
            '<span class="result-state-symbol result-state-symbol-warn" aria-hidden="true">'
            '<svg viewBox="0 0 24 24">'
            '<path class="warn-tri" d="M12 4 L21 20 H3 Z"/>'
            '<line class="warn-line" x1="12" y1="9" x2="12" y2="14"/>'
            '<circle class="warn-dot" cx="12" cy="18" r="1.1"/>'
            '</svg></span>'
        )
    if icon == "❗️":
        return (
            '<span class="result-state-symbol result-state-symbol-bang" aria-hidden="true">'
            '<svg viewBox="0 0 24 24">'
            '<line class="bang-line" x1="12" y1="5" x2="12" y2="15"/>'
            '<circle class="bang-dot" cx="12" cy="19" r="1.3"/>'
            '</svg></span>'
        )
    if icon == "↻":
        return (
            '<span class="result-state-symbol result-state-symbol-loop" aria-hidden="true">'
            '<svg viewBox="0 0 24 24">'
            '<path class="loop-arrow" d="M17.6 7.2A7 7 0 1 0 19 12"/>'
            '<path class="loop-head" d="M17.6 3.8v3.4h3.4"/>'
            '</svg></span>'
        )
    return ""


