@app.get("/", response_class=HTMLResponse)
def home(request: Request):
    selected_package_id = normalize_package_id(request.query_params.get("package")) or "p1"
    selected_plan = get_package_plan(selected_package_id) if selected_package_id else None
    selected_amount = selected_plan.amount if selected_plan else _safe_amount(request.query_params.get("amount") or PACKAGE_PRICE)
    selected_name = selected_plan.name if selected_plan else PACKAGE_NAME
    recent_rows = _payment_attempt_history_rows(hours=24, limit=12)
    if recent_rows:
        recent_items = [_render_attempt_history_item(r, "%H:%M") for r in recent_rows]
        recent_history_html = f"<div class='history-box'>{''.join(recent_items)}</div>"
    else:
        legacy_rows = _payment_history_rows(hours=24, limit=12)
        recent_items = []
        for r in legacy_rows:
            code = str(r["v"] or "")
            short_code = code[:14] + "…" + code[-8:] if len(code) > 28 else code
            try:
                ts_text = time.strftime("%H:%M", time.localtime(int(r["first_seen_at"] or 0)))
            except Exception:
                ts_text = "-"
            amount = ""
            if "amount" in r.keys() and r["amount"] not in (None, ""):
                amount = f"<span class='history-amount'>{escape(str(r['amount']))} บาท</span>"
            recent_items.append(f"<div class='history-item'><div class='history-code'>ซอง {escape(short_code)}</div><div class='history-time'>{escape(ts_text)}</div>{amount}</div>")
        recent_history_html = f"<div class='history-box'>{''.join(recent_items)}</div>" if recent_items else "<div class='history-box'><div class='history-empty'>ยังไม่มีประวัติทำรายการล่าสุด</div></div>"

    recent_history_html = "<div class='history-box' id='recentHistoryBox'><div class='history-empty'>Loading recent payments...</div></div>"

